import { useState } from "react";
import { motion } from "framer-motion";
import { Plus, Trash2, ChevronDown, ChevronUp } from "lucide-react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


const GRADE_POINTS: Record<string, number> = { "A+": 4.0, "A": 4.0, "A-": 3.7, "B+": 3.3, "B": 3.0, "B-": 2.7, "C+": 2.3, "C": 2.0, "C-": 1.7, "D+": 1.3, "D": 1.0, "D-": 0.7, "F": 0.0 };
const GRADE_OPTIONS = Object.keys(GRADE_POINTS);

const FAQS = [
  { q: "How is GPA calculated?", a: "GPA = BP(Grade Points  x  Credit Hours) / BP(Credit Hours). Multiply each course's grade points by its credit hours, sum all products, then divide by total credit hours attempted." },
  { q: "What is a good GPA?", a: "A 3.5+ GPA is considered excellent and may qualify for Latin honors (cum laude). 3.0-3.49 is good. 2.5-2.99 is average. Many graduate programs and employers prefer a 3.0+ minimum." },
  { q: "What is the difference between GPA and cumulative GPA?", a: "Semester GPA is calculated for courses taken in a single term. Cumulative GPA includes all courses taken across all semesters. Most transcripts show both; employers and graduate schools typically look at cumulative GPA." },
  { q: "How much does one bad grade affect GPA?", a: "Impact depends on credit hours. A 3-credit F in a 60-credit curriculum drops a 3.5 GPA to approximately 3.32. Higher-credit courses have proportionally more impact. Retaking and grade forgiveness policies vary by institution." },
  { q: "What GPA do I need for honors?", a: "Summa cum laude typically requires 3.9+. Magna cum laude requires 3.7-3.89. Cum laude requires 3.5-3.69. Exact thresholds vary by institution - some use class rank instead of fixed GPA cutoffs." },
  { q: "Does a W (withdrawal) affect my GPA?", a: "A W (withdrawal) typically does NOT affect your GPA. However, it may affect your completion rate (academic progress), which can impact financial aid eligibility. Check your institution's specific policies." },
  { q: "What is a 4.0 GPA in percentage?", a: "A 4.0 GPA corresponds to an A (93-100%). A 3.0 GPA = B (83-86%). A 2.0 GPA = C (73-76%). Exact conversions vary by school since some use A=90% and others use A=93%." },
  { q: "Can a low GPA be overcome in graduate school applications?", a: "Yes - strong GRE/GMAT scores, relevant research experience, compelling personal statements, and strong letters of recommendation can offset a low GPA. Many programs consider your last 60 credits separately if you showed improvement." },
];

export default function GPACalculator() {
  const [courses, setCourses] = useState([
    { name: "English 101", grade: "A", credits: 3 },
    { name: "Math 201", grade: "B+", credits: 4 },
    { name: "History 101", grade: "A-", credits: 3 },
    { name: "Biology 101", grade: "B", credits: 4 },
  ]);

  const totalCredits = courses.reduce((sum, c) => sum + c.credits, 0);
  const weightedPoints = courses.reduce((sum, c) => sum + (GRADE_POINTS[c.grade] ?? 0) * c.credits, 0);
  const gpa = totalCredits > 0 ? weightedPoints / totalCredits : 0;

  const add = () => setCourses([...courses, { name: `Course ${courses.length + 1}`, grade: "B", credits: 3 }]);
  const remove = (i: number) => setCourses(courses.filter((_, idx) => idx !== i));
  const update = (i: number, field: keyof typeof courses[0], value: string | number) => setCourses(courses.map((c, idx) => idx === i ? { ...c, [field]: value } : c));

  const gpaColor = gpa >= 3.5 ? "from-emerald-500 to-emerald-700" : gpa >= 3.0 ? "from-sky-500 to-sky-700" : gpa >= 2.0 ? "from-amber-500 to-amber-700" : "from-red-500 to-red-700";
  const gpaLabel = gpa >= 3.9 ? "A (Summa Cum Laude)" : gpa >= 3.7 ? "A- (Magna Cum Laude)" : gpa >= 3.5 ? "B+ (Cum Laude)" : gpa >= 3.0 ? "B (Good Standing)" : gpa >= 2.0 ? "C (Satisfactory)" : "D/F (Academic Risk)";

  return (
    <>
      <SEOHead
        title="Free GPA Calculator Online - Calculate Semester and Cumulative GPA Instantly | CalcHive"
        description="Free online GPA calculator. Calculate your semester or cumulative GPA from course grades and credit hours instantly. 100% free for all students, no signup required."
        canonical="/gpa-calculator"
        keywords="free GPA calculator, GPA calculator online free, cumulative GPA calculator free, semester GPA calculator free, calculate college GPA free"
        category="Math Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free GPA Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free GPA calculator to calculate college GPA free from course grades and credit hours. This GPA calculator online free works as a cumulative GPA calculator free and semester GPA calculator free for college and high school students.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-3 mb-6">
            <div className="grid grid-cols-12 gap-2 text-xs font-semibold text-muted-foreground px-1">
              <span className="col-span-5">Course</span>
              <span className="col-span-3 text-center">Grade</span>
              <span className="col-span-3 text-center">Credits</span>
              <span className="col-span-1" />
            </div>
            {courses.map((c, i) => (
              <div key={i} className="grid grid-cols-12 gap-2 items-center">
                <input value={c.name} onChange={e => update(i, "name", e.target.value)} className="col-span-5 px-3 py-2 rounded-lg border border-input bg-background text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40" />
                <select value={c.grade} onChange={e => update(i, "grade", e.target.value)} className="col-span-3 px-2 py-2 rounded-lg border border-input bg-background text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40">
                  {GRADE_OPTIONS.map(g => <option key={g} value={g}>{g}</option>)}
                </select>
                <input type="number" value={c.credits} min={1} max={6} onChange={e => update(i, "credits", Number(e.target.value))} className="col-span-3 px-2 py-2 rounded-lg border border-input bg-background text-sm text-center text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40" />
                <button onClick={() => remove(i)} className="col-span-1 p-1 text-muted-foreground hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
              </div>
            ))}
          </div>
          <button onClick={add} className="flex items-center gap-2 text-sm font-semibold text-primary hover:bg-accent px-3 py-1.5 rounded-lg transition-colors mb-8">
            <Plus className="w-4 h-4" /> Add Course
          </button>
          <motion.div key={JSON.stringify(courses)} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`bg-gradient-to-br ${gpaColor} rounded-2xl p-6 mb-4 text-center shadow-lg`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">GPA</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-gpa">{gpa.toFixed(2)}</p>
              <p className="text-white/70 text-sm mt-1">{gpaLabel}</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[{ label: "Total Credits", value: `${totalCredits} hrs` }, { label: "Quality Points", value: weightedPoints.toFixed(1) }, { label: "Courses", value: `${courses.length}` }].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your GPA for Free</h2>
          <p className="text-muted-foreground leading-relaxed">GPA is a weighted average where courses with more credit hours have more influence. Each grade is converted to grade points (A = 4.0, B = 3.0, etc.), then multiplied by credit hours. The total quality points are divided by total credit hours.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Quality Points = Grade Points  x  Credit Hours</p>
            <p>GPA = Total Quality Points  x  Total Credit Hours</p>
            <p className="text-xs text-muted-foreground mt-2">Example: A (4.0) in 3-credit course = 12 quality points</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find Semester vs Cumulative GPA</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Letter Grade", "Grade Points", "Percentage Range", "Description"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["A+ / A", "4.0", "93-100%", "Excellent"],
                  ["A-", "3.7", "90-92%", "Excellent"],
                  ["B+", "3.3", "87-89%", "Above Average"],
                  ["B", "3.0", "83-86%", "Good"],
                  ["B-", "2.7", "80-82%", "Good"],
                  ["C+", "2.3", "77-79%", "Average"],
                  ["C", "2.0", "73-76%", "Average"],
                  ["C-", "1.7", "70-72%", "Below Average"],
                  ["D+", "1.3", "67-69%", "Passing (barely)"],
                  ["D", "1.0", "63-66%", "Passing (minimum)"],
                  ["D-", "0.7", "60-62%", "Passing (marginal)"],
                  ["F", "0.0", "0-59%", "Failing"],
                ].map(([grade, points, pct, desc]) => (
                  <tr key={grade} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{grade}</td>
                    <td className="py-2.5 px-4 text-amber-600 dark:text-amber-400 font-semibold">{points}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{pct}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{desc}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free College and High School GPA Tool for Every Student</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free tool on any device to solve the calculation instantly, check your work, and get a clear result without downloads or signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/gpa-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


